// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.9;

import {PartiallyPausableInternal} from "@solidstate/contracts/security/partially_pausable/PartiallyPausableInternal.sol";
import {PausableInternal} from "@solidstate/contracts/security/pausable/PausableInternal.sol";
import {PackStorage} from "./PackStorage.sol";
import {IAvatarNFT} from "../../interfaces/IAvatarNFT.sol";
import {IHorseNFT} from "../../interfaces/IHorseNFT.sol";
import {ContractType} from "../../utils/constants.sol";
import {AccessControlInternal} from "@solidstate/contracts/access/access_control/AccessControlInternal.sol";

contract PackFacet is
    PartiallyPausableInternal,
    PausableInternal,
    AccessControlInternal
{
    // using PackStorage for PackStorage.Layout;

    event PackPurchased(
        uint256 indexed packId,
        address indexed buyer,
        uint256 quantity
    );

    bytes32 constant PACK_PURCHASES_PAUSED = "PACK_PURCHASES_PAUSED";

    error PackNotActive(uint256 packId);
    error MaxPerTxExceeded(uint256 requested, uint256 maxAllowed);
    error InvalidEthTotal(uint256 sentEth, uint256 requiredEth);

    function purchasePack(uint256 packId, uint256 quantity) external payable {
        PackStorage.Pack memory pack = PackStorage.getPack(packId);

        if (!pack.isActive) {
            revert PackNotActive(packId);
        }

        if (pack.maxPurchasePerTx < quantity) {
            revert MaxPerTxExceeded(quantity, pack.maxPurchasePerTx);
        }

        if ((pack.pricePerPack * quantity) != msg.value) {
            revert InvalidEthTotal(msg.value, (pack.pricePerPack * quantity));
        }

        // Get the addresses of the assets in the pack and the quantity of each
        uint256 assetsLength = pack.assets.length;
        uint256 i; // Defaults to zero, saves gas by not initializing
        for (; i < assetsLength; ) {
            //  Depending on contract type, call a specific function to mint the asset
            if (pack.assets[i].assetType == ContractType.Avatar) {
                IAvatarNFT(pack.assets[i].assetAddress).mint(
                    msg.sender,
                    pack.assets[i].amount * quantity
                );
            } else if (pack.assets[i].assetType == ContractType.HorseV2) {
                // JSH: Was going to do HorseV1 as well I don't think we need to support that anymore
                IHorseNFT(pack.assets[i].assetAddress).externalMint(
                    pack.assets[i].seasonId,
                    pack.assets[i].payoutTier,
                    pack.assets[i].amount * quantity,
                    msg.sender
                );
            }

            unchecked {
                ++i;
            }
        }

        emit PackPurchased(packId, msg.sender, quantity);
    }

    // Retrieves a pack by ID
    function getPack(
        uint256 packId
    ) external view returns (PackStorage.Pack memory) {
        return PackStorage.getPack(packId);
    }

    // Retrieves all pack IDs
    function getAllPackIds() external view returns (uint256[] memory) {
        return PackStorage.getAllPackIds();
    }

    // Retrieves all active packs
    function getActivePacks()
        external
        view
        returns (PackStorage.Pack[] memory)
    {
        return PackStorage.getActivePacks();
    }
}

contracts/facets/pack/PackStorage.sol.content:
// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.9;

import {EnumerableSet} from "@openzeppelin/contracts/utils/structs/EnumerableSet.sol";
import {ContractType} from "../../utils/constants.sol";

library PackStorage {
    using EnumerableSet for EnumerableSet.UintSet;

    error PackDoesNotExist(uint256 packId);
    error PackAlreadyExists(uint256 packId);

    struct PackAsset {
        uint256 amount; // Quantity of the asset
        address assetAddress; // Contract address of the asset
        ContractType assetType; // Type of asset
        uint256 seasonId; // Season ID of the asset (HorseV2) or 0 for other assets
        uint256 payoutTier; // Payout tier of the asset (HorseV2) or 0 for other assets
    }

    struct Pack {
        // bool exists; // Indicates if the pack exists to avoid using a separate mapping or array
        PackAsset[] assets; // Array of assets included in the pack
        uint256 pricePerPack; // Price per pack
        uint256 maxPurchasePerTx; // Maximum number of packs purchasable in a single transaction
        bool isActive; // Indicates if the pack is currently active and purchasable
    }

    bytes32 internal constant STORAGE_SLOT =
        keccak256("silks.contracts.storage.Packs");

    struct Layout {
        EnumerableSet.UintSet packIds; // Set of all pack IDs
        mapping(uint256 => Pack) packs; // Mapping from pack ID to Pack details
    }

    function layout() internal pure returns (Layout storage l) {
        bytes32 slot = STORAGE_SLOT;
        assembly {
            l.slot := slot
        }
    }

    function addPack(
        PackAsset[] memory assets,
        uint256 pricePerPack,
        uint256 maxPurchasePerTx,
        bool isActive
    ) internal returns (uint256) {
        Layout storage l = layout();
        uint256 packId = l.packIds.length();

        if (l.packIds.contains(packId)) {
            revert PackAlreadyExists(packId);
        }

        l.packIds.add(packId);
        Pack storage newPack = l.packs[packId];
        newPack.pricePerPack = pricePerPack;
        newPack.maxPurchasePerTx = maxPurchasePerTx;
        newPack.isActive = isActive;

        // Manually copy each element from the memory array to the storage array
        for (uint i = 0; i < assets.length; i++) {
            newPack.assets.push(assets[i]);
        }

        return packId;
    }

    function updatePack(
        uint256 packId,
        PackAsset[] memory assets,
        uint256 pricePerPack,
        uint256 maxPurchasePerTx,
        bool isActive
    ) internal {
        Layout storage l = layout();
        if (!l.packIds.contains(packId)) {
            revert PackDoesNotExist(packId);
        }

        Pack storage pack = l.packs[packId];
        delete pack.assets; // Clear the existing assets array
        for (uint i = 0; i < assets.length; i++) {
            pack.assets.push(assets[i]); // Copy each asset from the memory array to the storage array
        }
        pack.pricePerPack = pricePerPack;
        pack.maxPurchasePerTx = maxPurchasePerTx;
        pack.isActive = isActive;
    }

    function removePack(uint256 packId) internal {
        Layout storage l = layout();
        if (!l.packIds.contains(packId)) {
            revert PackDoesNotExist(packId);
        }
        l.packIds.remove(packId);
        delete l.packs[packId];
    }

    function packExists(uint256 packId) internal view returns (bool) {
        Layout storage l = layout();
        return l.packIds.contains(packId);
    }

    function getPack(uint256 packId) internal view returns (Pack memory) {
        Layout storage l = layout();
        require(l.packIds.contains(packId), "Pack does not exist");
        return l.packs[packId];
    }

    function getAllPackIds() internal view returns (uint256[] memory) {
        Layout storage l = layout();
        uint256[] memory ids = new uint256[](l.packIds.length());
        for (uint256 i = 0; i < ids.length; i++) {
            ids[i] = l.packIds.at(i);
        }
        return ids;
    }

    function getActivePacks() internal view returns (Pack[] memory) {
        Layout storage l = layout();
        uint256 count = 0;
        for (uint256 i = 0; i < l.packIds.length(); i++) {
            if (l.packs[l.packIds.at(i)].isActive) {
                count++;
            }
        }

        Pack[] memory activePacks = new Pack[](count);
        uint256 index = 0;
        for (uint256 i = 0; i < l.packIds.length(); i++) {
            uint256 id = l.packIds.at(i);
            if (l.packs[id].isActive) {
                activePacks[index] = l.packs[id];
                index++;
            }
        }
        return activePacks;
    }
}

